    13→/**
    14→ * Integration tests for taxonomy (enum) properties.
    15→ * Tests that object properties pointing to classes with named individuals
    16→ * are mapped to string enums in OpenAPI.
    17→ */
    18→public class TaxonomyPropertyIT {
    19→
    20→  private static ReadContext spec;
    21→
    22→  @BeforeAll
    23→  static void setup() {
    24→    spec = TestUtil.getGeneratedSpec(
    25→        TestUtil.asFilePath(TaxonomyPropertyIT.class, "/regression/configs/config_taxonomy.yaml"));
    26→  }
    27→
    28→  @Test
    29→  void statusTaxonomyCreatesEnumFromIndividuals() {
    30→    // The Status taxonomy should create an array with items containing enum values
    31→    assertNotNull(spec.read("$.components.schemas.TaxonomyTest.properties.Status"));
    32→
    33→    // Taxonomy properties generate as arrays with items.enum
    34→    List<String> enumValues = spec.read("$.components.schemas.TaxonomyTest.properties.Status.items.enum", List.class);
    35→
    36→    assertNotNull(enumValues, "Status should have enum values");
    37→    assertTrue(enumValues.contains("Active"), "Enum should contain 'Active'");
    38→    assertTrue(enumValues.contains("Inactive"), "Enum should contain 'Inactive'");
    39→    assertTrue(enumValues.contains("Pending"), "Enum should contain 'Pending'");
    40→  }
    41→
    42→  @Test
    43→  void priorityTaxonomyCreatesEnumFromIndividuals() {
    44→    // The Priority taxonomy should create an array with items containing enum values
    45→    assertNotNull(spec.read("$.components.schemas.TaxonomyTest.properties.Priority"));
    46→
    47→    // Taxonomy properties generate as arrays with items.enum
    48→    List<String> enumValues = spec.read("$.components.schemas.TaxonomyTest.properties.Priority.items.enum", List.class);
    49→
    50→    assertNotNull(enumValues, "Priority should have enum values");
    51→    assertTrue(enumValues.contains("Low"), "Enum should contain 'Low'");
    52→    assertTrue(enumValues.contains("Medium"), "Enum should contain 'Medium'");
    53→    assertTrue(enumValues.contains("High"), "Enum should contain 'High'");
    54→  }
    55→
    56→  @Test
    57→  void taxonomyPropertyIsArrayType() {
    58→    // Taxonomy properties with someValuesFrom generate as arrays
    59→    assertEquals("array", spec.read("$.components.schemas.TaxonomyTest.properties.Status.type"));
    60→    assertEquals("array", spec.read("$.components.schemas.TaxonomyTest.properties.Priority.type"));
    61→  }
    62→
    63→  @Test
    64→  void taxonomyPropertyHasMinItems() {
    65→    // someValuesFrom implies at least one value
    66→    assertEquals(1, spec.read("$.components.schemas.TaxonomyTest.properties.Status.minItems", Integer.class));
    67→    assertEquals(1, spec.read("$.components.schemas.TaxonomyTest.properties.Priority.minItems", Integer.class));
    68→  }
