    14→/**
    15→ * Test that a simple API (employer) gets generated correctly.
    16→ *
    17→ * <ul>
    18→ *  <li>Api has title, description, termsOfService, contact, version, x-grl-api-label, x-grl-graph-namespace in info.</li>
    19→ *  <li>Api has Employee and Employer resources.</li>
    20→ *  <li>each resource has single and collection endpoints.</li>
    21→ *  <li>each endpoint has standard methods.</li>
    22→ *  <li>each method has standard parameters and responses.</li>
    23→ *  <li>resources have basic properties only.</li>
    24→ * </ul>
    25→ */
    26→public class SimpleApiIT {
    27→
    28→  ReadContext employeeSpec = TestUtil.getGeneratedSpec(
    29→      TestUtil.asFilePath(SimpleApiIT.class, "config_employee.yaml"));
    30→
    31→  @Test
    32→  public void withEmployeeInfoIsCorrect() {
    33→    assertEquals("EmploymentAPIV1.0.1", employeeSpec.read("$.info.title"));
    34→    assertEquals("Minimal Test API", employeeSpec.read("$.info.description"));
    35→    assertEquals("some terms", employeeSpec.read("$.info.termsOfService"));
