    56→  @Test
    57→  void testObjectSomeValuesFrom() {
    58→    // TestClass subClassOf (hasProperty some TargetClass)
    59→    var restriction = factory.getOWLObjectSomeValuesFrom(hasProperty, targetClass);
    60→    var axiom = factory.getOWLSubClassOfAxiom(testClass, restriction);
    61→    manager.addAxiom(ontology, axiom);
    62→
    63→    SchemaVisitor visitor = new SchemaVisitor(testClass, ontology, owlThing, "", false);
    64→    testClass.accept(visitor);
    65→
    66→    Map<String, Set<RestrictionInfo>> restrictions = visitor.getRestrictions();
    67→    assertTrue(restrictions.containsKey("hasProperty"), "Should contain hasProperty");
    68→
    69→    Set<RestrictionInfo> infos = restrictions.get("hasProperty");
    70→    assertEquals(1, infos.size(), "Should have one restriction");
    71→    assertInstanceOf(RestrictionInfo.SomeValuesFrom.class, infos.stream().findFirst().orElseThrow(),
    72→        "Should be SomeValuesFrom restriction");
    73→
    74→    Set<String> objectProps = visitor.getObjectPropertyNames();
    75→    assertTrue(objectProps.contains("hasProperty"), "Should track property name");
    76→  }
